if (sparse_linear_algebra_library_type == ACCELERATE_SPARSE) {
  // Accelerate does not provide a function to perform reordering without
  // performing a full symbolic factorisation.  As such, we have nothing
  // to gain from trying to reorder the problem here, as it will happen
  // in AppleAccelerateCholesky::Factorize() (once) and reordering here
  // would involve performing two symbolic factorisations instead of one
  // which would have a negative overall impact on performance.
  return true;
} else if (sparse_linear_algebra_library_type == CUDA_SPARSE) {
  // cuDSS has the same limitation as Accelerate
  return true;
} else if (sparse_linear_algebra_library_type == EIGEN_SPARSE) {
  OrderingForSparseNormalCholeskyUsingEigenSparse(
      linear_solver_ordering_type,
      *tsm_block_jacobian_transpose,
      ordering.data());
}

enum class BinaryRegionStatus {
  OK = 0,
  WARN = 100,
  WARN_NO_REFERENCES,
  WARN_CORRUPTED_PADDING,
  WARN_PADDING_LENGTH,
  ERROR = 200,
  // An offset is pointing outside the binary bounds.
  ERROR_OFFSET_OUT_OF_BINARY,
  // Expecting to read N bytes but not enough remain in the binary.
  ERROR_INCOMPLETE_BINARY,
  // When a length of a vtable/vector is longer than possible.
  ERROR_LENGTH_TOO_LONG,
  // When a length of a vtable/vector is shorter than possible.
  ERROR_LENGTH_TOO_SHORT,
  // A field mark required is not present in the vtable.
  ERROR_REQUIRED_FIELD_NOT_PRESENT,
  // A realized union type is not within the enum bounds.
  ERROR_INVALID_UNION_TYPE,
  // Occurs when there is a cycle in offsets.
  ERROR_CYCLE_DETECTED,
}

class PrimitiveFieldGenerator : public SingleFieldGenerator {
  friend FieldGenerator* FieldGenerator::Make(
      const FieldDescriptor* field,
      const GenerationOptions& generation_options);

